insert into scenarios (id, type, payload) values (
  'linear-keyboard',
  'daily',
  '{"id":"linear-keyboard","type":"daily","scheduled_date":"","company":"Linear","era":"2019 — early product","context":"Linear launched into a market dominated by Jira, Asana, and ClickUp — tools that competed on configurability. Linear''s first-screen experience pushed almost every action behind a keyboard shortcut, and the onboarding actively taught the shortcuts before showing the GUI.","prompt":"What is the most interesting choice the team made in this onboarding — and what''s the bet beneath it?","reveal_quote":"We optimized for the daily user, not the first-time user. The cost of a steep first day is a flat curve forever after. Most tools optimize the opposite way and never recover.","reveal_quote_attribution":"Karri Saarinen, Linear cofounder/CEO — paraphrased from public interviews","reveal_note":"The choice that''s easy to miss: Linear was willing to lose users in the first 10 minutes to win the next 10 years. Most PMs would file ''keyboard-shortcut-first onboarding'' under UX risk. The team filed it under positioning — the tool selects for users who want a tool that selects for them. The shortcut is the brand.","quote_type":"paraphrased","sources":[{"title":"Inside Linear: Building with taste, craft, and focus | Karri Saarinen","url":"https://www.lennysnewsletter.com/p/inside-linear-building-with-taste","publisher":"Lenny''s Newsletter","year":2024,"type":"podcast"},{"title":"How Linear became the new Jira","url":"https://www.runtime.news/how-linear-became-the-new-jira/","publisher":"Runtime","type":"article"}],"tags":{"industry":"devtools","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'stripe-docs',
  'daily',
  '{"id":"stripe-docs","type":"daily","scheduled_date":"","company":"Stripe","era":"2011 — launch","context":"Stripe''s launch homepage was almost entirely code. Seven lines of Ruby, copy-pasteable. No marketing video, no enterprise CTA, no testimonials. Just the integration. PayPal''s homepage at the time led with security badges and merchant logos.","prompt":"What is the most interesting choice the team made on this homepage — and who is it for?","reveal_quote":"The homepage isn''t for buyers. It''s for the developer who''s going to recommend us to their boss. If the developer can run the code in 30 seconds, the conversation upstream is already over.","reveal_quote_attribution":"Patrick Collison — paraphrased from early Stripe interviews and coverage","reveal_note":"The non-obvious move: Stripe inverted the buyer. Payments was sold as a procurement decision; Stripe rebuilt it as a developer decision. The homepage is a recruiting tool aimed at the person inside the customer who will champion you. Most B2B PMs design pages for the person who signs the contract — Stripe designed for the person who picks up the API key.","quote_type":"paraphrased","sources":[{"title":"How Two Brothers Turned Seven Lines of Code Into a $9.2 Billion Startup","url":"https://www.bloomberg.com/news/features/2017-08-01/how-two-brothers-turned-seven-lines-of-code-into-a-9-2-billion-startup","publisher":"Bloomberg","year":2017,"type":"article"},{"title":"How the Collison brothers turned ''seven lines of code'' into Stripe","url":"https://news.ycombinator.com/item?id=14902696","publisher":"Hacker News","year":2017,"type":"article"}],"tags":{"industry":"fintech","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'notion-ai-bundle',
  'daily',
  '{"id":"notion-ai-bundle","type":"daily","scheduled_date":"","company":"Notion","era":"2023 — Notion AI launch","context":"Notion launched AI in February 2023 as a $10/user/month add-on rather than baking it into the existing plans. Most competitors (including office-suite incumbents) folded AI into base pricing or made it free for paid users.","prompt":"What''s the most interesting choice in pricing AI as a separate add-on — and what does it tell you about how Notion sees the feature?","reveal_quote":"If we''d bundled it, we''d never know what people would pay for it. Pricing is a measurement instrument before it''s a revenue decision.","reveal_quote_attribution":"Notion product team — paraphrased from public commentary around the Notion AI launch","reveal_note":"What''s easy to miss: bundling looks like generosity but throws away the most valuable signal in a feature launch — willingness to pay. Notion treated the $10 line as a research instrument, not a paywall. The output isn''t ''is this feature profitable'' — it''s ''which users care enough to switch from free AI tools to a paid integrated one,'' which then tells you whether to invest more or retreat.","quote_type":"paraphrased","sources":[{"title":"Notion''s lost years, near collapse during Covid, the joy and suffering of building horizontal | Ivan Zhao","url":"https://www.lennysnewsletter.com/p/inside-notion-ivan-zhao","publisher":"Lenny''s Podcast","year":2025,"type":"podcast"},{"title":"Notion launches AI agent as it crosses $500 million in annual revenue","url":"https://www.cnbc.com/2025/09/18/notion-launches-ai-agent-as-it-crosses-500-million-in-annual-revenue.html","publisher":"CNBC","year":2025,"type":"article"}],"tags":{"industry":"productivity","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'dropbox-demo-video',
  'daily',
  '{"id":"dropbox-demo-video","type":"daily","scheduled_date":"","company":"Dropbox","era":"2008 — pre-private-beta","context":"Spring 2008. Dropbox has ~5,000 beta signups and a product that''s still flaky. Instead of polishing the funnel, Drew Houston posts a 4-minute screencast on Digg and Hacker News — a deadpan demo with deliberate inside-jokes aimed at the Digg and Reddit crowd. There''s no marketing copy, no testimonials. The video shows the product solving a problem the audience has, in their own language.","prompt":"Why ship a demo video to Digg before the product even works for the audience watching — and what is the video actually testing?","reveal_quote":"We weren''t trying to sell the product, we were trying to find out if the product was worth building. The video was the cheapest version of the product we could ship.","reveal_quote_attribution":"Drew Houston, Dropbox cofounder/CEO — paraphrased from Y Combinator and Lenny''s Newsletter retellings","reveal_note":"The non-obvious move: a demo video is a free MVP. The product wasn''t ready; the demand was the thing being tested. The result — the beta waitlist jumped from 5,000 to 75,000 overnight — wasn''t growth, it was a market signal. The lesson: when you can''t ship the product, ship the smallest artifact that lets the market vote with intent, not opinion. Surveys ask people what they want; a signup form asks them to pay (in attention) to want it.","quote_type":"paraphrased","sources":[{"title":"Behind the founder: Drew Houston (Dropbox)","url":"https://www.lennysnewsletter.com/p/behind-the-founder-drew-houston-dropbox","publisher":"Lenny''s Newsletter","type":"podcast"},{"title":"Drew Houston on the original Dropbox HN post","url":"https://x.com/drewhouston/status/1904948248961315299","publisher":"X / Drew Houston","type":"tweet"},{"title":"Dropbox doing things that don''t scale","url":"https://www.alexanderjarvis.com/dropbox-doing-things-that-dont-scale/","type":"blog"}],"tags":{"industry":"saas","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'airbnb-photographers',
  'daily',
  '{"id":"airbnb-photographers","type":"daily","scheduled_date":"","company":"Airbnb","era":"Summer 2009","context":"Airbnb has been stuck at about $200/week in revenue for eight months. The founders are running out of money. Looking at their worst-performing listings, they notice a pattern: the photos are terrible — flip-phone snapshots, blurry, badly lit. The ''obvious'' fix is to write better seller guides, or build a UI that nudges hosts to upload more photos. Instead Brian Chesky and Joe Gebbia fly to New York, borrow professional cameras, and personally photograph 24 hosts'' apartments. Revenue doubles to $400 that week.","prompt":"Why fly to New York and become photographers themselves, when there are obviously cheaper ways to fix listing photos?","reveal_quote":"Do things that don''t scale. Until you''ve talked to your users in their kitchens, you don''t actually know what''s broken. Software is the last step, not the first.","reveal_quote_attribution":"Paul Graham / Brian Chesky — paraphrased from ''Do Things That Don''t Scale'' (essay and retellings)","reveal_note":"The choice that''s easy to miss: founders solving the problem with their hands generates a kind of insight that a dashboard cannot. The photo issue was symptomatic — what they actually learned in those apartments was that hosts didn''t understand they were running a hospitality business, not renting a room. That insight became the entire ''Belong Anywhere'' brand and the design of the host onboarding. The lesson is not ''send photographers''; it''s that low-leverage in-person work in the early days is often the only way to find the high-leverage product changes.","quote_type":"paraphrased","sources":[{"title":"How Airbnb doubled revenue in one week","url":"https://strategybreakdowns.com/p/airbnb-photography","publisher":"Strategy Breakdowns","type":"article"},{"title":"Do Things That Don''t Scale","url":"http://paulgraham.com/ds.html","publisher":"Paul Graham","year":2013,"type":"blog"},{"title":"When Airbnb was young: the early years","url":"https://vator.tv/2016-02-26-when-airbnb-was-young-the-early-years/","publisher":"VatorNews","year":2016,"type":"article"}],"tags":{"industry":"marketplace","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'spotify-free-tier',
  'daily',
  '{"id":"spotify-free-tier","type":"daily","scheduled_date":"","company":"Spotify","era":"October 2008 — launch in Sweden/UK/France","context":"Spotify launches in 2008 with a free, ad-supported tier alongside a paid premium tier. The major labels hate it. Apple iTunes is selling tracks at 99¢. Pandora has built a US business on free streaming. Spotify''s wager is more aggressive: any song, on demand, free forever, with ads — and a frictionless upgrade to ad-free paid. Internally, the metric to beat is not Apple''s revenue per user. It''s the BitTorrent download.","prompt":"Why give the catalog away free, in a market where the dominant legal alternative is a 99¢ paid download — and who is Spotify actually competing with?","reveal_quote":"The enemy was not the free listener. The enemy was piracy. If we could give people something legal that was as easy as stealing, the free tier was a cost of doing business, not a revenue leak.","reveal_quote_attribution":"Daniel Ek, Spotify cofounder/CEO — paraphrased from public interviews","reveal_note":"The non-obvious move: Spotify mis-identified its competitor on purpose. iTunes was the surface comp; BitTorrent was the real one. Once you frame the competitor as piracy, every product decision flips — free is a feature not a leak, ads are a tax cheaper than theft, and the upgrade to premium is not ''pay for music'' but ''pay to remove the ad inserted to compete with free piracy.'' Most PMs benchmark to the visible competitor in the same category. The win was benchmarking to the invisible one.","quote_type":"paraphrased","sources":[{"title":"Spotify just turned 20 — how Daniel Ek built a $100B music empire","url":"https://fortune.com/article/spotify-20-year-anniversary-daniel-ek-founder-ceo-music-industry-least-powerful-person/","publisher":"Fortune","year":2026,"type":"article"},{"title":"Spotify — Wikipedia","url":"https://en.wikipedia.org/wiki/Spotify","type":"article"}],"tags":{"industry":"media","region":"eu","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'slack-internal-tool',
  'daily',
  '{"id":"slack-internal-tool","type":"daily","scheduled_date":"","company":"Slack","era":"2013 — pivot from Glitch","context":"Tiny Speck spent three years and ~$17M of investor money building Glitch, a browser MMO. The game flops. The team has burned most of the runway. But they have one asset: an internal IRC-like chat tool they built so the distributed team could ship the game. The ''rational'' play is to wind the company down and return remaining capital. Instead Stewart Butterfield tells investors he''s pivoting to ship the internal tool — to other companies — as a product.","prompt":"What''s the non-obvious bet in pivoting to your own internal tool — and what makes the bet defensible against the dozens of existing chat products?","reveal_quote":"If our team can''t live without it, that''s the strongest demand signal you can have. The competition wasn''t HipChat, it was email. Email is what we replaced for ourselves; that''s what we''d replace for other teams.","reveal_quote_attribution":"Stewart Butterfield, Slack cofounder/CEO — paraphrased from launch-era interviews","reveal_note":"What''s easy to miss: ''dogfooding'' is usually framed as a quality lever — you use it, so you fix the bugs. Slack used it as a positioning lever. The product didn''t need to beat HipChat (a similar tool); it needed to beat email (a totally different category). Reframing the competitor turned a crowded chat market into an underserved replacement-for-email market, and made every email-style feature (threads, search, archives) a wedge instead of a parity feature. Internal tools that become products tend to inherit a positioning insight, not just a feature set.","quote_type":"paraphrased","sources":[{"title":"The Slack origin story","url":"https://techcrunch.com/2019/05/30/the-slack-origin-story/","publisher":"TechCrunch","year":2019,"type":"article"},{"title":"Stewart Butterfield''s letter: We Don''t Sell Saddles Here","url":"https://medium.com/@stewart/we-dont-sell-saddles-here-4c59524d650d","publisher":"Medium / Stewart Butterfield","year":2014,"type":"blog"}],"tags":{"industry":"saas","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'figma-browser-bet',
  'daily',
  '{"id":"figma-browser-bet","type":"daily","scheduled_date":"","company":"Figma","era":"2012–2016 — pre-launch","context":"Sketch dominates UI design in the early 2010s. The category-defining tool is a native macOS app — single user, single machine, .sketch files passed around in Slack. Dylan Field and Evan Wallace take ~$4M of seed money and spend four years building a design tool from scratch — in the browser, with multiplayer editing, before launching anything in public. Most designers hate the demos. Browsers are seen as too slow for serious creative work.","prompt":"Why bet four years on a browser-based, multiplayer design tool when designers — your users — are openly skeptical of the technology?","reveal_quote":"We bet on a thing nobody wanted yet because the thing they did want — desktop files, single-player — was structurally incapable of doing what design teams were going to need next.","reveal_quote_attribution":"Dylan Field, Figma cofounder/CEO — paraphrased from public interviews and the Index Ventures retrospective","reveal_note":"The choice that''s easy to miss: users tell you what they want from inside the current paradigm. Designers in 2013 wanted faster Sketch, not browser-Sketch. Figma''s bet was that the latent need — design as a team activity, with handoff baked in — would only become visible once the artifact (the .sketch file) was no longer the unit of work. The technology was a wedge for a workflow change, not a feature upgrade. Listening to users would have built a better single-player tool. Listening to the trajectory built the multiplayer one.","quote_type":"paraphrased","sources":[{"title":"Designers hated Figma at first, but grew to love it","url":"https://techcrunch.com/2023/06/25/figma-design-tool-history/","publisher":"TechCrunch","year":2023,"type":"article"},{"title":"Figma Goes Public: Thirteen Unforgettable Years with Dylan Field","url":"https://www.indexventures.com/perspectives/figma-goes-public-thirteen-unforgettable-years-with-dylan-field/","publisher":"Index Ventures","year":2025,"type":"blog"},{"title":"Design Meet the Internet | Figma Blog","url":"https://www.figma.com/blog/design-meet-the-internet/","publisher":"Figma","type":"blog"}],"tags":{"industry":"devtools","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'patagonia-dont-buy-this-jacket',
  'daily',
  '{"id":"patagonia-dont-buy-this-jacket","type":"daily","scheduled_date":"","company":"Patagonia","era":"November 25, 2011 — Black Friday","context":"Black Friday 2011. Patagonia takes out a full-page ad in the New York Times. Above a photo of their R2 fleece sits the headline: ''Don''t Buy This Jacket.'' The body copy details the water, carbon, and waste cost of producing the jacket — and asks the reader not to buy it unless they need it. Every other retailer that morning is running discount-driven ads. Patagonia is asking shoppers to spend less.","prompt":"What is Patagonia actually optimizing for with an ad that tells customers not to buy on the highest-volume shopping day of the year?","reveal_quote":"We''re in business to save our home planet. If our customers buy a jacket they don''t need, we''ve failed at the mission, even if we made the sale.","reveal_quote_attribution":"Yvon Chouinard, Patagonia founder — paraphrased from public commentary around the Common Threads Initiative","reveal_note":"What''s easy to miss: the ad is a selection filter, not a sales lever. It''s recruiting the customer who buys Patagonia because of what Patagonia means, not because the jacket is on sale. That customer cohort is far more profitable over a lifetime than the discount-hunter, even at lower per-purchase frequency. Patagonia''s sales reportedly rose ~30% in the year following the ad. The lesson isn''t ''reverse psychology''; it''s that brand statements that cost you the wrong customers earn you the right ones.","quote_type":"paraphrased","sources":[{"title":"Don''t Buy This Jacket, Black Friday and the New York Times","url":"https://www.patagonia.com/stories/planet/activism/dont-buy-this-jacket-black-friday-and-the-new-york-times/story-18615.html","publisher":"Patagonia","year":2011,"type":"blog"},{"title":"The Secret History of ''Don''t Buy This Jacket''","url":"https://davidgelles.substack.com/p/the-secret-history-of-dont-buy-this","publisher":"David Gelles","type":"blog"}],"tags":{"industry":"ecommerce","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'whatsapp-no-ads-note',
  'daily',
  '{"id":"whatsapp-no-ads-note","type":"daily","scheduled_date":"","company":"WhatsApp","era":"2012 — pre-Facebook acquisition","context":"WhatsApp at this point is the fastest-growing messenger in the world. Above Jan Koum''s desk hangs a note from cofounder Brian Acton: ''No Ads, No Games, No Gimmicks.'' The default monetization for a free messaging app — pre-2014 — is ads. WhatsApp instead charges $0.99 per year and writes a manifesto on the company blog explaining why advertising-as-business-model is a betrayal of the user. Investors are uneasy. Sequoia funds them only after explicitly agreeing not to push an ad model.","prompt":"What''s the non-obvious move in publicly rejecting ads and charging $0.99/yr instead — and what is the $1 actually doing?","reveal_quote":"When advertising is involved, you the user are the product being sold. We wanted the user to be the customer. Charging a dollar is the cheapest possible way to make that true.","reveal_quote_attribution":"Jan Koum, WhatsApp cofounder — from the official WhatsApp blog post ''Why we don''t sell ads'' (2012)","reveal_note":"The choice that''s easy to miss: the dollar isn''t revenue — it''s an alignment instrument. A free user has no contract with you; a paying user does. The $0.99/yr is too low to fund the company (Sequoia knew this), but it converts the relationship from attention-broker to service-provider. Acton''s note above the desk is a forcing function: every product decision is constrained by it. Most consumer apps say they care about users; WhatsApp engineered a constraint that made them care, structurally, by giving up the easy money. The Facebook acquisition in 2014 eventually broke this — and both founders left over it.","quote_type":"verbatim","sources":[{"title":"Why we don''t sell ads","url":"https://blog.whatsapp.com/why-we-don-t-sell-ads","publisher":"WhatsApp Blog","year":2012,"type":"blog"},{"title":"WhatsApp introduces ads, fulfilling a plan its cofounders hated so much they left over it","url":"https://fortune.com/2025/06/16/whatsapp-ads-cofounders-jan-koum-brian-acton/","publisher":"Fortune","year":2025,"type":"article"},{"title":"Jan Koum — Wikipedia","url":"https://en.wikipedia.org/wiki/Jan_Koum","type":"article"}],"tags":{"industry":"communication","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'wechat-super-app-2011',
  'daily',
  '{"id":"wechat-super-app-2011","type":"daily","scheduled_date":"","company":"Tencent (WeChat)","era":"January 2011 — launch","context":"October 2010. Allen Zhang, a Tencent VP running their email product, sends Pony Ma (Tencent CEO) a midnight email arguing that Kik (a US messaging app that just launched) is the start of an existential threat. Tencent already has QQ — China''s dominant desktop IM with hundreds of millions of users. Building a separate mobile messenger risks cannibalizing QQ. Pony Ma replies with four characters — ''马上就办'' (''do it now''). Zhang assembles a team of ten and ships WeChat in 60 days. Within two years it absorbs payments, mini-programs, social feed, and government services.","prompt":"Why ship a new mobile-first messenger that cannibalizes your dominant desktop product — and why so fast?","reveal_quote":"If we don''t kill QQ, someone else will. The only question is who eats the cannibalization — us or a competitor we can''t see yet.","reveal_quote_attribution":"Allen Zhang / Pony Ma — paraphrased from internal-Tencent retellings of the WeChat origin","reveal_note":"The non-obvious move: most incumbents protect the cash cow and let a small team build the next thing slowly. Tencent did the opposite — they let the new product cannibalize the old one openly, on the explicit assumption that platform shifts are won by whoever moves first, not by whoever transitions cleanly. The 60-day shipping window was not a feat of execution; it was a strategic claim that the cost of being late was orders of magnitude larger than the cost of imperfect launch. Most US companies in this scenario protect the existing revenue line. Tencent staked the company on the opposite bet.","quote_type":"paraphrased","sources":[{"title":"The Panic That Built WeChat''s $700 Billion Super-App","url":"https://howardyu.substack.com/p/the-panic-that-built-wechats-700","type":"blog"},{"title":"WeChat history: the rise of the super app","url":"https://chinatechscope.com/history-of-wechat/","publisher":"ChinaTechScope","type":"article"},{"title":"WeChat — Wikipedia","url":"https://en.wikipedia.org/wiki/WeChat","type":"article"}],"tags":{"industry":"consumer-social","region":"asia","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'taobao-free-vs-ebay',
  'daily',
  '{"id":"taobao-free-vs-ebay","type":"daily","scheduled_date":"","company":"Alibaba (Taobao)","era":"May 2003 — China launch vs. eBay","context":"eBay has just acquired EachNet — China''s online auction leader — for $180M, giving it ~80% market share. eBay charges sellers per-listing and per-transaction fees, the model that built its US dominance. Alibaba launches Taobao, a competing C2C marketplace, with one promise: listings will be free for the first three years. eBay''s response in the press is dismissive: ''Free is not a business model.''","prompt":"What is Alibaba actually buying with three years of free listings — and what is eBay misreading about the China market?","reveal_quote":"eBay was selling a service to sellers. We were buying sellers themselves. Once we had the supply, the demand had nowhere else to go.","reveal_quote_attribution":"Jack Ma, Alibaba founder — paraphrased from public interviews around the Taobao vs. eBay era","reveal_note":"The choice that''s easy to miss: ''free'' wasn''t a price, it was a customer-acquisition channel that paid in supply. Sellers — not buyers — are the scarce side of a marketplace. eBay treated sellers as monetizable users; Taobao treated sellers as the product. The three-year window was long enough that any seller migration was sticky by the time fees would have applied. eBay''s market share dropped from ~80% to ~30% in two years; eBay China shut down in 2006. The deeper lesson: in two-sided markets, charging the wrong side first kills you slowly. Free-on-supply is rarely free — it''s investment.","quote_type":"paraphrased","sources":[{"title":"Taobao — Wikipedia","url":"https://en.wikipedia.org/wiki/Taobao","type":"article"},{"title":"How Alibaba took on eBay in China (and a few lessons for entrepreneurs)","url":"https://medium.com/@aishsinhaindia/how-alibaba-took-on-ebay-in-china-and-a-few-lessons-for-indian-entrepreneurs-4f5ae9709089","type":"blog"}],"tags":{"industry":"marketplace","region":"asia","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'aws-s3-launch',
  'daily',
  '{"id":"aws-s3-launch","type":"daily","scheduled_date":"","company":"Amazon Web Services","era":"March 14, 2006 — S3 launch","context":"Amazon launches S3 — Simple Storage Service — with a one-paragraph announcement on the ''What''s New'' page. No keynote, no analyst briefing, no enterprise sales motion. Pricing is $0.15/GB-month with no minimums and no contracts. The target customer is a single developer with a credit card. Internally at Amazon, retail leadership had pushed for an enterprise-sales motion; Werner Vogels and the AWS team explicitly fought to keep S3 self-service, API-only, no human touch.","prompt":"Why launch infrastructure that enterprise CIOs would happily pay 100x for as a self-serve, credit-card, API-only product instead — and what is that pricing actually signaling?","reveal_quote":"If you make a developer fill out a form to talk to a salesperson, you''ve already lost. The developer is the buyer; the procurement department is downstream. Build for the developer first.","reveal_quote_attribution":"Werner Vogels, Amazon CTO — paraphrased from public AWS reinvent keynotes and interviews","reveal_note":"The non-obvious move: per-GB billing wasn''t pricing, it was a positioning signal. By making infrastructure consumable in the same dollar-units a college kid uses, AWS told the market ''this is for builders, not buyers.'' Enterprise sales motions actively repel the early-adopter developer. Amazon flipped the funnel — get the developer first, let them carry AWS into their company. Every infrastructure company that followed (Stripe, Twilio, Snowflake, Datadog) inherited this playbook. The price-per-GB was the marketing.","quote_type":"paraphrased","sources":[{"title":"Twenty years of Amazon S3 and building what''s next","url":"https://aws.amazon.com/blogs/aws/twenty-years-of-amazon-s3-and-building-whats-next/","publisher":"AWS News Blog","year":2026,"type":"blog"},{"title":"Amazon Web Services Launches","url":"https://press.aboutamazon.com/2006/3/amazon-web-services-launches","publisher":"Amazon Press Center","year":2006,"type":"press-release"},{"title":"Happy 15th Birthday Amazon S3","url":"https://www.allthingsdistributed.com/2021/03/happy-15th-birthday-amazon-s3.html","publisher":"Werner Vogels / All Things Distributed","year":2021,"type":"blog"}],"tags":{"industry":"infra","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'wise-hidden-fees',
  'daily',
  '{"id":"wise-hidden-fees","type":"daily","scheduled_date":"","company":"Wise (formerly TransferWise)","era":"2011–2015 — launch through brand-build","context":"Kristo Käärmann and Taavet Hinrikus are two Estonians living in London who lose hundreds of pounds in ''free'' bank transfers because of hidden FX markups. They build Wise (then TransferWise) with one rule for the brand: every marketing surface compares Wise''s real fee against the bank''s hidden fee, named and quantified. Naked PR stunts in 2014–2015 — including a London street-protest where Wise employees strip down to skin-tone underwear next to signs reading ''nothing to hide'' — push the campaign into mainstream press.","prompt":"Why anchor a financial-services brand on a single, aggressive enemy framing — ''banks lie about their fees'' — instead of leading with product features?","reveal_quote":"We didn''t build a remittance product. We built a transparency product that happens to move money. The fee comparison is the whole pitch — feature parity is table stakes.","reveal_quote_attribution":"Kristo Käärmann, Wise cofounder/CEO — paraphrased from public interviews around the #Nothing2Hide era","reveal_note":"What''s easy to miss: in a category dominated by trust (financial services), the standard play is to look more like a bank. Wise did the opposite — they framed every bank as the antagonist and made themselves the unauthorized truth-teller. That positioning came with a real cost: regulators, banking partners, and brand-conscious enterprises wouldn''t touch them. The benefit: zero ad-spend on customer acquisition through their first few million users, because every fee-comparison post functioned as both ad and protest. Brand-as-enemy-framing works when the enemy is structurally guilty and the consumer''s grievance is real. The competitor pays your customer-acquisition cost.","quote_type":"paraphrased","sources":[{"title":"Wise (company) — Wikipedia","url":"https://en.wikipedia.org/wiki/Wise_(company)","type":"article"},{"title":"4 FinTech Marketing Strategies: Wise''s Journey to Industry Disruption","url":"https://www.extole.com/blog/4-fintech-marketing-strategies-wises-journey-to-industry-disruption/","publisher":"Extole","type":"blog"},{"title":"Story of Wise: Wanted Fair Rates. Oops, Built a Fintech Empire.","url":"https://yourfintechstory.com/story-of-wise-wanted-fair-rates-oops-built-a-fintech-empire/","type":"blog"}],"tags":{"industry":"fintech","region":"uk","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'twilio-pay-as-you-go',
  'daily',
  '{"id":"twilio-pay-as-you-go","type":"daily","scheduled_date":"","company":"Twilio","era":"2008–2010 — founding through SMS launch","context":"Telecom in 2008 sells the same product (SMS, voice routing) two ways: enterprise contracts with six-month negotiations and per-seat licensing, or low-quality consumer aggregator APIs. Twilio launches with a third model — pay-per-message, pay-per-minute, no contracts, no minimums, credit-card self-serve, full programmable API. A startup can send its first SMS within five minutes of signing up. Carriers and incumbent telecom-API competitors are skeptical that ''real'' customers will commit to a per-unit pricing model.","prompt":"Why launch programmable telecom with per-message pricing and zero contract friction, when the entire industry is built around long-term enterprise commitments?","reveal_quote":"We weren''t selling minutes; we were selling permission. Permission for a single developer at 2am to integrate global telecom without asking anyone. The pricing model was the permission.","reveal_quote_attribution":"Jeff Lawson, Twilio cofounder/CEO — paraphrased from ''Ask Your Developer'' and public interviews","reveal_note":"The choice that''s easy to miss: per-call pricing isn''t a discount, it''s a sales-cycle eliminator. Enterprise telecom contracts have a six-month sales cycle and a six-figure minimum. Twilio''s pricing made the sales cycle zero, but at the cost of giving up the high-margin commitments that fund the sales team. The implicit bet: if you serve 100,000 developers with no salespeople, the revenue per developer doesn''t matter — it''s the volume. Stripe, AWS, Sendgrid, Datadog all run this same playbook. The pricing page is the sales team.","quote_type":"paraphrased","sources":[{"title":"How Did Twilio Build a Multi-Billion Dollar Empire With Usage-Based Pricing?","url":"https://www.getmonetizely.com/articles/how-did-twilio-build-a-multi-billion-dollar-empire-with-usage-based-pricing","publisher":"Monetizely","type":"article"},{"title":"Twilio — Wikipedia","url":"https://en.wikipedia.org/wiki/Twilio","type":"article"}],"tags":{"industry":"devtools","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'zoom-40-minute-limit',
  'daily',
  '{"id":"zoom-40-minute-limit","type":"daily","scheduled_date":"","company":"Zoom","era":"2013 — launch","context":"Zoom launches its consumer-facing freemium tier in 2013 with a deliberate constraint: group meetings on the free plan are capped at 40 minutes. One-on-one meetings are unlimited. Competitor freemium products (Skype, GoToMeeting trials, Google Hangouts) impose limits on participant count or features, not duration. The cap is uncomfortable enough to feel during a single meeting, but small enough that solo users barely notice.","prompt":"Why pick 40 minutes as the friction point — and what is the limit actually testing?","reveal_quote":"The free tier is the demo, not the product. The 40 minutes is exactly long enough to show that Zoom works better than what they had before, and exactly short enough that they''ll feel it when it cuts off.","reveal_quote_attribution":"Eric Yuan, Zoom founder/CEO — paraphrased from public interviews about Zoom''s freemium model","reveal_note":"The non-obvious move: the constraint is engineered to fire at the moment of highest demonstrated value. At 40 minutes, the meeting has already produced something — momentum, decisions, a working relationship with the tool. Cutting off there forces the upgrade conversation when the willingness-to-pay is highest. Most freemium tiers cap based on what''s cheap to give away (storage, seats, features). Zoom capped based on what''s psychologically expensive to lose mid-task. The constraint is not a cost limit; it''s a conversion mechanism.","quote_type":"paraphrased","sources":[{"title":"Understanding time limits for Zoom Meetings","url":"https://support.zoom.com/hc/en/article?id=zm_kb&sysparm_article=KB0067966","publisher":"Zoom Support","type":"documentation"},{"title":"Zoom (software) — Wikipedia","url":"https://en.wikipedia.org/wiki/Zoom_(software)","type":"article"}],"tags":{"industry":"communication","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-app-store-70-30',
  'daily',
  '{"id":"apple-app-store-70-30","type":"daily","scheduled_date":"","company":"Apple","era":"July 10, 2008 — App Store launch","context":"Steve Jobs spent the first year of the iPhone (2007) publicly refusing to allow third-party apps — he wanted Apple to control the experience end to end. A year later he reverses course. The App Store launches with 552 apps and a clean revenue split: developer keeps 70%, Apple takes 30%, free apps cost nothing to publish. Music labels by comparison still take ~50–70% of artist revenue. Standard retail software at the time keeps publishers/distributors closer to 60% of retail price.","prompt":"Why give 70% to third-party developers when Apple controls the only distribution channel — and what is the 30% buying for Apple?","reveal_quote":"The 30% isn''t rent. It''s the cost of running the only store in the world that comes pre-installed on every device in the customer''s pocket. The developer wouldn''t take 100% on a worse store; we don''t have to take more than 30% on the best one.","reveal_quote_attribution":"Steve Jobs — paraphrased from the 2008 iPhone SDK keynote and subsequent public statements","reveal_note":"What''s easy to miss: 70/30 was simultaneously generous to developers and an aggressive moat for Apple. Generous, because it inverted the publishing economics of every prior platform (retail software, music labels, magazine distribution). Aggressive, because it locked third-party developers into a single store with bundled payment, hosting, and distribution — pricing the alternatives (build your own store, sideloading, web apps) out of competitiveness for over a decade. The fight that''s now public (Epic v. Apple, EU DMA) is about who captured the surplus from that decision. The original move was a positioning statement: ''we will be the developer-friendly platform'' — which then turned into structural lock-in.","quote_type":"paraphrased","sources":[{"title":"Steve Jobs introduces the App Store — iPhone SDK Keynote","url":"https://www.youtube.com/watch?v=xo9cKe_Fch8","publisher":"Apple / YouTube","year":2008,"type":"video"},{"title":"Apple''s App Store changed the software world 17 years ago","url":"https://appleinsider.com/articles/23/01/15/apples-app-store-changed-the-software-world-15-years-ago","publisher":"AppleInsider","type":"article"},{"title":"The revolution Steve Jobs resisted: Apple''s App Store marks 10 years","url":"https://appleinsider.com/articles/18/07/10/the-revolution-steve-jobs-resisted-apples-app-store-marks-10-years-of-third-party-innovation","publisher":"AppleInsider","year":2018,"type":"article"}],"tags":{"industry":"saas","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'tesla-direct-sales',
  'daily',
  '{"id":"tesla-direct-sales","type":"daily","scheduled_date":"","company":"Tesla","era":"2012 — Model S launch and the franchise-law fights","context":"Every U.S. state has a franchise-dealer law that requires new cars to be sold through independent dealerships, not directly by manufacturers. The laws were written to protect dealers from manufacturer abuse and they make manufacturer-direct sales effectively illegal in most states. Tesla launches the Model S in 2012 selling exclusively direct — company-owned stores, no dealers. Multiple state dealer associations sue. Tesla cannot legally sell cars in several states for years; in Massachusetts, an early Tesla store is allowed to display vehicles but not actually take orders.","prompt":"Why refuse the legal, established distribution channel — and accept years of state-level lawsuits — when dealers would happily sell the car for you?","reveal_quote":"A dealer''s incentive is to sell whatever margin is highest today. Ours is to convert someone from a gas car for life. Those two incentives aren''t different by a little — they''re opposite. We couldn''t license that gap to anyone.","reveal_quote_attribution":"Elon Musk — paraphrased from Tesla''s public commentary on direct sales (2012–2015)","reveal_note":"The choice that''s easy to miss: distribution is part of the product. A dealership selling Teslas next to gas cars has an incentive to actively up-sell against the EV (gas cars carry higher service-revenue tails). Tesla couldn''t build a category-changing product through agents whose existing business depended on the category not changing. The legal fight wasn''t a side effect — it was a brand asset, because every state battle generated press that reinforced Tesla as the disruptor. The deeper lesson: when your product requires customer education that contradicts your distributor''s interests, the distributor is not neutral. Owning the channel is sometimes the only way to own the message.","quote_type":"paraphrased","sources":[{"title":"Tesla US dealership disputes — Wikipedia","url":"https://en.wikipedia.org/wiki/Tesla_US_dealership_disputes","type":"article"},{"title":"Tesla and the Car Dealers'' Lobby","url":"https://www.cato.org/regulation/summer-2014/tesla-car-dealers-lobby","publisher":"Cato Institute","year":2014,"type":"article"},{"title":"Tesla fought to sell cars direct to customers, and now more carmakers want in","url":"https://www.marketplace.org/story/2026/04/22/why-arent-more-cars-sold-directly-to-consumers","publisher":"Marketplace","year":2026,"type":"article"}],"tags":{"industry":"hardware","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'warby-parker-home-try-on',
  'daily',
  '{"id":"warby-parker-home-try-on","type":"daily","scheduled_date":"","company":"Warby Parker","era":"February 15, 2010 — launch","context":"Glasses are a $95+ purchase that buyers nearly universally want to try on. The industry assumption circa 2010 is that eyewear cannot meaningfully be sold online — return rates would crush the margin. Warby Parker launches with a counterintuitive feature: customers pick five frames on the website; Warby ships all five to their home for free; the customer keeps one (or none) and returns the rest at zero cost. Within 48 hours of GQ calling them ''the Netflix of eyewear,'' inventory is overwhelmed and the home-try-on program is paused.","prompt":"Why ship five physical frames to every customer who hasn''t paid yet — and what is Warby Parker buying with the shipping cost?","reveal_quote":"We weren''t selling glasses online. We were selling permission to try without committing. Once the box is in the customer''s hand, the conversion job is already done.","reveal_quote_attribution":"Neil Blumenthal, Warby Parker cofounder — paraphrased from public interviews on the home-try-on program","reveal_note":"The non-obvious move: the program isn''t a feature, it''s the entire customer-acquisition strategy. Five frames in the customer''s home for five days does three things in parallel: it eliminates the try-on objection (the only structural barrier to online eyewear), it triples the conversation about the brand (people show friends the frames at home), and it pre-qualifies the buyer (anyone willing to fill out the form is high-intent). The shipping cost is the marketing budget — a customer-acquisition channel that''s almost impossible for incumbents to copy without restructuring their entire returns infrastructure. The lesson: friction-removal at the highest-friction step in the funnel often pays for itself many times over, even when the unit cost looks crazy.","quote_type":"paraphrased","sources":[{"title":"The Mistake That Turned Warby Parker Into an Overnight Legend","url":"https://www.inc.com/magazine/201505/graham-winfrey/neil-blumenthal-icons-of-entrepreneurship.html","publisher":"Inc. Magazine","year":2015,"type":"article"},{"title":"Warby Parker — Wikipedia","url":"https://en.wikipedia.org/wiki/Warby_Parker","type":"article"},{"title":"Warby Parker''s Home Try-On: How a Logistical Experiment Became a Brand-Building Engine","url":"https://www.markhub24.com/post/warby-parker-s-home-try-on-how-a-logistical-experiment-became-a-brand-building-engine","type":"blog"}],"tags":{"industry":"ecommerce","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'meta-threads-2023',
  'weekly',
  '{"id":"meta-threads-2023","type":"weekly","iso_week":"","company":"Meta","era":"Early 2023","intro":"It is early 2023. You are a senior PM at Meta. Twitter has been acquired by Elon Musk and is in active turmoil — verification chaos, advertiser pullback, mass layoffs, and a steady exodus of the cultural-influencer cohort who made the platform sticky.\n\nMark Zuckerberg''s leadership team is debating whether Meta should ship a text-based social app. Internally there is a working prototype built on the Instagram codebase. The Instagram graph is the largest social graph in the Western world (~2B MAU). A text product could in theory bootstrap on it instantly.","open_questions":["Tightly couple to Instagram (one-tap signup, IG followers ported in), or stand alone?","What ships at launch? DMs? Hashtags? A chronological feed? A web app?","Is the goal to kill Twitter, complement Instagram, or defend against TikTok absorbing text-social mindshare?","How big is the risk an obvious Twitter-clone gets dismissed by users and press as derivative?"],"closing":"Imagine you''re in the room. You don''t yet know what they decided or how it played out.","decision":"Ship as a tightly-coupled extension of Instagram. One-tap signup with IG credentials. IG followers auto-suggested. Built and shipped by the IG team in roughly five months. Deliberately omitted at launch: DMs, hashtags, trending topics, web app, chronological feed default, following-only feed, ability to delete Threads without deleting Instagram.","pullquote":"Not to replace Twitter, but to build a public square for communities on Instagram that never really embraced Twitter.","pullquote_attribution":"Adam Mosseri, Head of Instagram, July 2023 — paraphrased / compressed from his public statements","outcomes":[{"stat":"100M","label":"signups in 5 days — fastest consumer launch ever"},{"stat":"−80%","label":"DAU within 3 weeks of launch","accent":true},{"stat":"12 mo","label":"deliberate slow rollout: web, search, hashtags, following feed"},{"stat":"~150M","label":"MAU by end of 2024 — durable growth, not retention curve"}],"tradeoffs":[{"title":"Speed-to-market vs. product polish","body":"Meta knew the launch product was thin. They optimized for shipping during Twitter''s instability window — a market-timing call, not a product-completeness call."},{"title":"Growth-hack coupling vs. user trust","body":"The IG-account lock-in was a deliberate growth lever they expected to reverse. They ate the trust hit on purpose because the alternative was a much slower S-curve."},{"title":"''Defend'' framing vs. ''kill Twitter'' framing","body":"The actual goal was defensive — keep text-social inside the Meta ecosystem rather than let X or TikTok own it. The Twitter-killer narrative was press, not strategy."},{"title":"Retention-now vs. retention-later","body":"They explicitly tolerated the DAU collapse. The internal metric that mattered was 6-month and 12-month retained MAU, not week-1 DAU."}],"per_dimension_truth":{"tradeoff":"Speed-to-market and ecosystem defense vs. product depth. They sacrificed launch-week retention and user trust to ship inside Twitter''s instability window.","user":"Existing Instagram users who were curious about text social but had never adopted Twitter — explicitly not the existing Twitter power-user cohort.","alt":"Decoupled launch with DMs and a web app would have shipped slower and lost the timing window. Meta chose the opposite trade.","predict":"Massive launch-week numbers, fast collapse, then slow durable growth — a 12-month bet, not a 12-week one."},"quote_type":"paraphrased","sources":[{"title":"Instagram Head Says Threads Isn''t Trying to ''Replace'' Twitter","url":"https://www.thewrap.com/threads-replace-twitter-goal-adam-mosseri-instagram/","publisher":"TheWrap","year":2023,"type":"article"},{"title":"Birth of Threads: Mark Zuckerberg called up Adam Mosseri to discuss the ''Twitter-killer''","url":"https://www.businesstoday.in/technology/news/story/birth-of-threads-mark-zuckerberg-called-up-instagram-head-adam-mosseri-late-at-night-to-discuss-the-twitter-killer-392003-2023-07-31","publisher":"Business Today","year":2023,"type":"article"},{"title":"Instagram head says Threads is ''not going to amplify news on the platform''","url":"https://techcrunch.com/2023/10/11/instagram-head-says-threads-is-not-going-to-amplify-news-on-the-platform/","publisher":"TechCrunch","year":2023,"type":"article"}],"tags":{"industry":"consumer-social","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'shopify-shop-2020',
  'weekly',
  '{"id":"shopify-shop-2020","type":"weekly","iso_week":"","company":"Shopify","era":"Early 2020","intro":"It is early 2020. You are a senior PM at Shopify. The company has spent a decade building infrastructure for merchants — Shopify is the picks-and-shovels of e-commerce, deliberately not consumer-facing.\n\nLeadership is debating launching Shop, a consumer mobile app for tracking orders across all Shopify merchants. It would put Shopify directly in front of end-shoppers for the first time. Some inside the company argue it''s a betrayal of the merchant-first promise. Others argue Amazon is going to eat every Shopify merchant alive if shoppers don''t have a unified buying surface outside Amazon.","open_questions":["Does building a consumer app cannibalize merchant brand? The whole pitch is ''your store, not ours.''","If shoppers see ''Shop'' as the brand, do merchants become commoditized fulfillment behind it?","Is the alternative — letting Amazon own discovery — actually worse for merchants?","What does ''success'' look like for a product whose users are not your customers?"],"closing":"Imagine you''re in that strategy room. You don''t yet know what they decide.","decision":"Ship Shop as a consumer app, but design it to elevate the merchant brand, not Shopify''s. Each merchant page in the app is fully merchant-branded. Shopify''s logo is nearly invisible in-app. The app''s core feature is package tracking — a real shopper need that has nothing to do with merchant identity. Discovery and recommendations were added cautiously over the next two years.","pullquote":"The app doesn''t make Shopify the brand. It makes Shopify invisible — which is the only way merchants will tolerate us being in front of their customers.","pullquote_attribution":"Tobi Lütke, Shopify CEO — paraphrased from public commentary around the Shop launch (2020–21)","outcomes":[{"stat":"100M+","label":"Shop app downloads by 2023"},{"stat":"Low","label":"Merchant churn from Shop launch — concerns didn''t materialize","accent":true},{"stat":"2 yrs","label":"Shopify deliberately delayed building strong recommendations"},{"stat":"$200M+","label":"GMV processed through Shop Pay weekly by 2023"}],"tradeoffs":[{"title":"Brand neutrality vs. brand visibility","body":"Shopify deliberately made itself invisible inside the app. The cost: weaker direct brand recall with shoppers. The benefit: merchants didn''t revolt."},{"title":"Tracking-as-Trojan-horse","body":"Package tracking is the most-checked feature in any shopper''s life. Shopify used the most boring use case as the wedge into a consumer relationship."},{"title":"Defensive vs. offensive framing","body":"Externally Shop looked like aggression. Internally it was framed as defense against Amazon owning discovery. The framing shaped what got built and what didn''t."},{"title":"Restraint as moat","body":"The team explicitly held back on personalized recommendations for two years. The discipline preserved merchant trust in a way a faster, AI-driven discovery push would have torched."}],"per_dimension_truth":{"tradeoff":"Defense against Amazon''s discovery monopoly vs. risking the merchant-first brand promise. Resolved by making Shopify invisible inside the consumer app.","user":"Shoppers who already buy from Shopify merchants and need package tracking — not new customer acquisition. The merchant is still the brand the shopper experiences.","alt":"A heavily Shopify-branded consumer app with strong recommendations would have driven faster consumer engagement and triggered merchant revolt. They chose restraint.","predict":"Slow consumer adoption initially, durable growth as Shop Pay became the actual flywheel — payments embedded across the merchant network."},"quote_type":"paraphrased","sources":[{"title":"Shopify launches consumer-facing shopping assistant app","url":"https://betakit.com/shopify-launches-consumer-facing-shopping-assistant-app/","publisher":"BetaKit","year":2020,"type":"article"},{"title":"Shopify — Wikipedia","url":"https://en.wikipedia.org/wiki/Shopify","type":"article"},{"title":"Masters of Scale: Be a platform, with Tobi Lütke","url":"https://mastersofscale.com/tobi-lutke-be-a-platform/","publisher":"Masters of Scale","type":"podcast"}],"tags":{"industry":"ecommerce","region":"anz","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'airbnb-covid-2020',
  'weekly',
  '{"id":"airbnb-covid-2020","type":"weekly","iso_week":"","company":"Airbnb","era":"March–May 2020","intro":"It is March 2020. You are a senior PM at Airbnb. COVID-19 has closed borders. Travel demand has fallen off a cliff — revenue is down roughly 80% in eight weeks, and the company is burning about $250M/month. The IPO that was supposed to land in 2020 is dead on arrival. The company has about 7,500 employees globally and a sprawling roadmap: Airbnb Experiences, Luxe, Plus, hotels, transportation.\n\nLeadership has to make three calls in parallel: how deep to cut, what to cut from the product portfolio, and how to position the company that emerges. The ''rational'' play is to cut everything that isn''t core stays and ride out the pandemic.","open_questions":["How deep to cut on headcount — enough to survive 12 months of zero recovery, or shallower bets on a faster rebound?","Kill Experiences/Luxe/Plus and refocus on core stays, or keep optionality across the portfolio?","How transparent to be publicly about the cuts and the rationale — does that help or hurt the long brand?","Is the IPO dead permanently, or just delayed — and how should the runway decision reflect each?"],"closing":"Imagine you''re in the executive room in early April 2020. The data is bad, the recovery curve is unknown, and the team is watching to see what cut you make.","decision":"Cut deep, cut once, and refocus. In May 2020 Airbnb laid off 1,900 employees — about 25% of staff. Leadership killed or paused most of the non-stays product portfolio (Experiences, Luxe, Plus, hotels, transportation work) and explicitly refocused the company on hosts and stays. Severance was 14 weeks + healthcare + an internal alumni hiring database; the layoff letter was published openly. Airbnb''s IPO landed in December 2020 — eight months after the cuts.","pullquote":"I have a deep feeling of love for all of you. We have a more focused business, and we are going to emerge stronger.","pullquote_attribution":"Brian Chesky, Airbnb cofounder/CEO — from his publicly-published May 2020 letter to staff","outcomes":[{"stat":"1,900","label":"employees laid off (25% of staff) in one cut","accent":true},{"stat":"14 wks","label":"severance + healthcare + alumni placement program"},{"stat":"$250M/mo","label":"burn rate at the time of decision"},{"stat":"Dec 2020","label":"IPO — 8 months after the cuts"},{"stat":"$100B+","label":"market cap at peak following IPO"}],"tradeoffs":[{"title":"Cut deep once vs. cut shallow twice","body":"Chesky chose a single deep cut over staged smaller ones. The internal logic: two rounds of layoffs destroys trust faster than one. The cost is over-cutting if recovery is fast; the benefit is one trauma instead of two."},{"title":"Refocus vs. preserve optionality","body":"Killing Experiences/Luxe/Plus meant abandoning years of investment. Leadership decided focus was a survival asset — narrow surface area, faster decisions, clearer story for hosts and shareholders."},{"title":"Public transparency vs. quiet handling","body":"The published letter and alumni database were a brand bet. They turned a layoff (usually a brand-negative event) into a hiring tailwind for the laid-off staff and a recruiting story for the survivors."},{"title":"Host-first vs. shareholder-first framing","body":"The IPO was the obvious 2020 metric. Chesky de-prioritized it explicitly and built the cut around the host relationship instead. The IPO arrived anyway because the host network held."}],"per_dimension_truth":{"tradeoff":"Speed and depth of cut vs. preserving optionality and trust. Resolved by cutting once, deeply, transparently — even though that closed off entire product lines they''d invested years in.","user":"Hosts, not guests, were the user the decision optimized for. Hosts carry the supply; without supply, demand recovery is meaningless. Refocusing on stays was a supply-side bet, not a demand-side one.","alt":"A shallower first cut + portfolio preservation would have looked safer in April 2020 and forced a second cut by year-end. Airbnb chose the opposite: one trauma, deep refocus.","predict":"Short-term pain (mass layoffs, killed product lines), faster-than-expected recovery driven by domestic / longer-stay travel, and an IPO landing inside the same calendar year as the cuts."},"quote_type":"verbatim","sources":[{"title":"A Message from Co-Founder and CEO Brian Chesky","url":"https://news.airbnb.com/a-message-from-co-founder-and-ceo-brian-chesky/","publisher":"Airbnb Newsroom","year":2020,"type":"press-release"},{"title":"Airbnb Cuts 1,900 Jobs, 25% Of Its Workforce, As Pandemic Freezes Travel","url":"https://www.npr.org/sections/coronavirus-live-updates/2020/05/05/850986054/airbnb-cuts-1-900-jobs-25-of-its-workforce-as-pandemic-freezes-travel","publisher":"NPR","year":2020,"type":"article"},{"title":"Airbnb CEO Brian Chesky Tells Adam Grant the Right Way to Do Mass Layoffs: ''Cut Deep''","url":"https://www.inc.com/nick-hobson/airbnb-ceo-brian-chesky-tells-adam-grant-right-way-to-do-mass-layoffs-cut-deep.html","publisher":"Inc.","type":"interview"}],"tags":{"industry":"marketplace","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'netflix-streaming-pivot-2007',
  'weekly',
  '{"id":"netflix-streaming-pivot-2007","type":"weekly","iso_week":"","company":"Netflix","era":"January 2007","intro":"It is late 2006. You are a senior PM at Netflix. The DVD-by-mail business is humming — about 6.3 million subscribers, healthy contribution margins, and a strong moat in distribution centers nationwide. The brand is the red envelope.\n\nReed Hastings has told the board that streaming is the next platform and Netflix has to be on it before bandwidth makes it obvious. The leadership team is debating how — and how aggressively — to launch ''Watch Now.'' Building a full streaming product means cannibalizing the DVD business that funds the company. It also means licensing content from the same studios that view Netflix as a wholesale customer, not a competitor. Bandwidth is still spotty. The catalog will be a fraction of the DVD library at launch.","open_questions":["Charge separately for streaming, or bundle it free with the DVD subscription to drive trial?","How aggressively to cannibalize the DVD business — slow-walk streaming, or actively migrate customers off discs?","What''s the catalog play? Pay through the nose for the best titles, or launch with cheap back-catalog and accept a thin library?","How public to be about the streaming bet — frame the company as ''streaming-first,'' or keep the DVD brand intact to protect cash flow?"],"closing":"Imagine you''re in the leadership room in late 2006. The DVD business is profitable, the streaming product is half-built, and the studios are watching how you posture.","decision":"Launch ''Watch Now'' on January 16, 2007 — bundled free with DVD subscriptions, no separate price. About 1,000 titles at launch, almost entirely back-catalog. Hastings publicly framed Netflix''s identity as a streaming company from day one, even though streaming was a fraction of revenue. Aggressively migrated customers from DVD to streaming through pricing changes in the years following, even when it hurt short-term retention (the 2011 Qwikster split was the public scar tissue).","pullquote":"Movies over the internet are coming, and at some point it is going to be a huge business. We started in DVD, but we don''t intend to die in DVD.","pullquote_attribution":"Reed Hastings, Netflix cofounder/CEO — paraphrased from public interviews in the 2007–2010 era","outcomes":[{"stat":"6.3M → 18.3M","label":"subscribers from 2006 to 2010 (~3x growth)"},{"stat":"1,000","label":"titles in the initial streaming catalog"},{"stat":"$0","label":"incremental price to DVD subscribers at launch"},{"stat":"2011","label":"Qwikster fiasco — public scar from the cannibalization","accent":true},{"stat":"$300B+","label":"peak market cap in the streaming era"}],"tradeoffs":[{"title":"Bundle vs. unbundle","body":"Bundling streaming free with DVD removed the ''will customers pay for it'' question and converted streaming into a feature. The cost: it took years to disentangle the pricing and the 2011 split blew up in the company''s face. Bundling bought speed of adoption at the cost of future pricing flexibility."},{"title":"Cannibalize-now vs. cannibalize-later","body":"The safer play was to protect DVD revenue and let streaming grow alongside. Hastings chose to migrate aggressively, even when it hurt — on the theory that platform shifts reward whoever owns the new platform, not whoever bridges cleanly."},{"title":"Catalog-thin vs. catalog-rich at launch","body":"Launching with ~1,000 back-catalog titles meant the streaming product was clearly worse than DVD for years. The bet: thin catalog + good UX + relentless investment beats waiting until the catalog is good enough to launch flawlessly."},{"title":"Brand-as-DVD vs. brand-as-streaming","body":"The DVD brand was an asset; restating Netflix as ''streaming-first'' put that asset at risk. Hastings made the public-narrative bet early, before the financials supported it, to force the company''s identity onto the new platform."}],"per_dimension_truth":{"tradeoff":"Speed-of-platform-transition vs. clean preservation of the DVD cash cow. Netflix chose speed and accepted the messy middle period (2007–2013), including the Qwikster reversal, as the cost.","user":"Existing DVD subscribers who would adopt streaming as a free feature first, then re-anchor their mental model of Netflix around streaming. Not new customers — the existing graph was the lever.","alt":"A paid streaming SKU launched alongside DVD would have protected revenue, allowed cleaner pricing later, and likely lost the platform window to Hulu or Amazon. Netflix chose the opposite trade.","predict":"Subscriber growth, public confusion / brand pain in the messy years, and eventual dominance once streaming infrastructure caught up — a 5-year trade, not a 1-year one."},"quote_type":"paraphrased","sources":[{"title":"Netflix''s Streaming Pivot Included a Surprisingly Harsh Decision","url":"https://colemaninsights.com/coleman-insights-blog/netflixs-streaming-pivot-included-a-surprisingly-harsh-decision","publisher":"Coleman Insights","type":"blog"},{"title":"Reed Hastings and Netflix''s Game-Changing Pivot to Streaming","url":"https://executiveanecdotes.substack.com/p/reed-hastings-and-netflixs-game-changing","type":"blog"},{"title":"Netflix History: How Streamer Killed Blockbuster, Dominated Hollywood","url":"https://variety.com/2025/film/news/netflix-history-killed-blockbuster-dominated-hollywood-1236342853/","publisher":"Variety","year":2025,"type":"article"}],"tags":{"industry":"media","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'apple-itunes-music-store-2003',
  'weekly',
  '{"id":"apple-itunes-music-store-2003","type":"weekly","iso_week":"","company":"Apple","era":"2002–April 28, 2003","intro":"It is late 2002. You are a senior PM at Apple. The iPod has been on the market for ~14 months. It''s a beautiful device but its software story is a mess — users have to rip their own CDs (slow), buy DRM-locked tracks from PressPlay or MusicNet (which barely work), or pirate from Napster successors. The labels — the ''Big Five'' at the time — are losing 20%+ of revenue per year to piracy and are paralyzed.\n\nSteve Jobs wants to build a digital music store inside iTunes. He''s been negotiating with each of the Big Five separately for months. The labels want subscriptions ($10–15/mo for all-you-can-eat) with strict DRM. Jobs wants single-track sales at $0.99 with permissive DRM (multiple device authorizations, unlimited CD burns). The legal teams at the labels are unconvinced. The iPod is also Mac-only at the time — the addressable market is ~3% of US PC users.","open_questions":["Subscriptions or single-track ownership? The labels want recurring revenue; Jobs wants the iTunes Store to feel like a record shop.","How aggressive can the DRM terms be without spooking the labels — and how permissive can they be without nuking the negotiation?","Ship Mac-only first (small TAM but full Apple control) or wait to ship a Windows version (10x TAM, but Apple''s never shipped consumer software for Windows)?","What''s the negotiating posture — frame Apple as the labels'' savior from piracy, or as their replacement?"],"closing":"Imagine you''re in the room with Jobs in early 2003. The labels are skeptical, the iPod is Mac-only, and piracy is taking 20% off the top of the industry every year.","decision":"Launch the iTunes Music Store on April 28, 2003 — Mac-only at first, with single-track $0.99 pricing, all five major labels signed, ~200,000 songs at launch. DRM was ''FairPlay'' but with deliberately permissive terms: unlimited CD burns, up to five authorized devices. iTunes for Windows shipped six months later in October 2003. Apple sold 1M songs in six days — a milestone they''d forecasted would take six months.","pullquote":"This will go down as a turning point for the music industry.","pullquote_attribution":"Steve Jobs, on stage at the iTunes Music Store launch — April 28, 2003","outcomes":[{"stat":"$0.99","label":"per-track price — Jobs''s red line in the label negotiation"},{"stat":"5 / 5","label":"of the Big Five labels signed at launch"},{"stat":"1M","label":"songs sold in the first 6 days (forecast was 6 months)","accent":true},{"stat":"70M","label":"songs sold in the first year"},{"stat":"Oct 2003","label":"iTunes for Windows shipped 6 months after launch"}],"tradeoffs":[{"title":"Ownership vs. subscription","body":"Labels wanted recurring revenue. Jobs insisted on track-ownership at a flat $0.99. The cost: lower lifetime revenue per buyer; the benefit: a frictionless purchase that matched the mental model of buying a CD. Subscription music wouldn''t take off for another 8 years (Spotify, 2011)."},{"title":"Permissive vs. punitive DRM","body":"The labels wanted strict DRM — no CD burns, single-device. Jobs gave them DRM (FairPlay) but engineered it to be the most permissive consumer DRM of its era. The cost: the labels never fully trusted the terms; the benefit: customers didn''t experience the store as a tax."},{"title":"Mac-first vs. Windows-first","body":"Launching Mac-only was a 3% TAM but kept the experience under Apple control end-to-end. Six months later they shipped Windows — by then the brand and the catalog were stable. Reversing the order would have stretched Apple''s consumer-software muscles too thin too early."},{"title":"Frame as savior vs. frame as replacement","body":"Jobs publicly framed the store as the labels'' answer to piracy — the savior narrative. Internally, Apple was building the infrastructure to disintermediate the labels eventually. The framing got the deals done; the substance changed the industry''s power balance permanently."}],"per_dimension_truth":{"tradeoff":"Customer-friendly purchasing (single-track ownership at $0.99) vs. label-friendly business terms (subscription + DRM). Jobs leaned hard on the customer side and used Apple''s small market share as a wedge — ''we''re not a threat, we''re a test market.''","user":"Mac users who already owned an iPod and were either pirating or unhappily ripping CDs. Familiar audience, narrow but high-intent. Windows users came six months later, once the store and the negotiations were stable.","alt":"A subscription-only store with strict DRM would have looked safer to the labels and felt like rental to customers. It wouldn''t have moved the iPod the way ownership did. Apple chose the opposite trade.","predict":"Fast initial sales (the constrained Mac/iPod audience was thirsty for a legal alternative), Windows expansion making the store the dominant digital music retailer within 18 months, and a 10-year window before subscription streaming caught up."},"quote_type":"verbatim","sources":[{"title":"Apple Launches the iTunes Music Store","url":"https://www.apple.com/newsroom/2003/04/28Apple-Launches-the-iTunes-Music-Store/","publisher":"Apple Newsroom","year":2003,"type":"press-release"},{"title":"Twenty Years Ago, Apple Launched the iTunes Music Store","url":"https://512pixels.net/2023/04/itunes-music-store-20-years/","publisher":"512 Pixels","year":2023,"type":"blog"},{"title":"iTunes'' 10th Anniversary: How Steve Jobs Turned the Industry Upside Down","url":"https://rollingstone.com/culture/culture-news/itunes-10th-anniversary-how-steve-jobs-turned-the-industry-upside-down-68985/amp","publisher":"Rolling Stone","type":"article"}],"tags":{"industry":"media","region":"us","decade":"2000s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'snap-rejects-facebook-2013',
  'weekly',
  '{"id":"snap-rejects-facebook-2013","type":"weekly","iso_week":"","company":"Snap Inc. (Snapchat)","era":"November 2013","intro":"It is November 2013. You are a senior PM at Snapchat. The app is two years old. It has roughly 350 million snaps sent per day. Revenue is zero. The team is 30 people in a Venice Beach house. Evan Spiegel is 23.\n\nMark Zuckerberg has offered to acquire Snapchat for $3 billion in cash. Tencent has separately offered $200M at a $4B valuation. Around the same time, Google reportedly tables a $4B all-cash offer. Most observers — including some Snapchat investors — think Spiegel should take the Facebook deal. The argument: Instagram-with-direct-messaging already shows Facebook will copy any feature Snap ships, and disappearing photos can be replicated. Spiegel and Bobby Murphy refuse all three.","open_questions":["What''s the actual probability that Facebook successfully clones the product if you reject the offer?","How do you value a pre-revenue product whose distinctive feature (ephemerality) is structurally easy to copy?","Is the offer ceiling or floor? Does saying no force a bidding war, or does it close the door?","What''s the existential downside scenario — Facebook copies, kills you slowly, and the next offer is $300M, not $3B?"],"closing":"Imagine you''re sitting with Spiegel and Murphy in late November 2013. The Wall Street Journal is about to report the $3B offer either way. You don''t know what comes next.","decision":"Reject all three offers — Facebook, Tencent, and Google. Stay independent. Spiegel publicly framed the rejection as long-term conviction in what Snapchat could become; internally, the bet was that ephemerality was a behavior, not a feature, and that the format would proliferate (Stories, AR, the camera-as-keyboard interface) faster than any clone could keep up. Snap goes public in March 2017 at a $24B valuation. Facebook clones Stories across Instagram, WhatsApp, and Facebook itself within three years.","pullquote":"I wish I could say it was wisdom — but I think Bobby and I just loved what we were doing. We loved what we were working on, and we believed in the future of it.","pullquote_attribution":"Evan Spiegel, Snap cofounder/CEO — public interviews recalling the rejection","outcomes":[{"stat":"$3B","label":"Facebook cash offer rejected","accent":true},{"stat":"$4B","label":"Google all-cash offer also rejected"},{"stat":"Mar 2017","label":"Snap IPO at ~$24B valuation"},{"stat":"Stories","label":"format cloned across IG, WhatsApp, and Facebook within 3 years"},{"stat":"~30%","label":"of teen DAUs Snap retained against the Facebook clones"}],"tradeoffs":[{"title":"Liquid certainty vs. illiquid optionality","body":"$3B in cash for two founders in their early 20s is generational money. Saying no traded certain wealth for optionality on a much larger outcome — and the option could expire if Facebook executed the clone well."},{"title":"Feature defensibility vs. behavior defensibility","body":"If ''disappearing photos'' is the moat, the offer should be taken — features can be cloned in months. Spiegel''s bet was on a behavior (the camera-as-conversation) that''s harder to clone because it requires building a different relationship with the user, not just shipping a feature."},{"title":"Independence vs. distribution","body":"Joining Facebook would have given Snap distribution to a 1B+ user base overnight. Independence kept the brand, the audience (teens explicitly opting out of Facebook), and the product roadmap intact — but at the cost of building distribution the hard way."},{"title":"Negotiate vs. refuse","body":"Spiegel didn''t counter-offer. Refusing outright signaled conviction (to investors, to the team, to future hires) in a way that ''let''s talk at $6B'' would not. The signaling value of the refusal was itself a strategic asset."}],"per_dimension_truth":{"tradeoff":"Certain wealth + distribution muscle vs. independent control of a product category Spiegel believed was about to become much larger. He bet the latter was a 10x outcome, not a 2x one, and treated the offer as ceiling not floor.","user":"Teens explicitly opting out of Facebook''s identity-permanent feed. Joining Facebook would have changed who Snap was for, even if the product survived. The user was the moat.","alt":"Taking $3B was the rational, statistically defensible move. The opposite trade — staying independent — only looks correct because the behavior bet paid off enough to survive Facebook''s clone. The downside scenario (Snap loses to IG Stories, IPOs at a fraction) was very live.","predict":"Facebook clones aggressively, Snap loses some growth ceiling but defends a teen-camera audience, IPO at a multiple of the rejected offer, and a 5-year fight to prove the format mattered more than the wrapper."},"quote_type":"verbatim","sources":[{"title":"Snapchat''s 23-Year-Old CEO Said No to $3 Billion From Facebook","url":"https://www.nbcnews.com/id/wbna53545955","publisher":"NBC News","year":2013,"type":"article"},{"title":"Facebook offered $3 billion for Snapchat. Evan Spiegel said no.","url":"https://slate.com/technology/2013/11/facebook-offered-3-billion-for-snapchat-evan-spiegel-said-no.html","publisher":"Slate","year":2013,"type":"article"},{"title":"Evan Spiegel explains why he didn''t sell Snapchat to Mark Zuckerberg for $3 billion","url":"https://www.startuparchive.org/p/evan-spiegel-explains-why-he-didn-t-sell-snapchat-to-mark-zuckerberg-for-3-billion","publisher":"Startup Archive","type":"interview"}],"tags":{"industry":"consumer-social","region":"us","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'atlassian-no-sales-team',
  'weekly',
  '{"id":"atlassian-no-sales-team","type":"weekly","iso_week":"","company":"Atlassian","era":"2002–2015 — founding through IPO","intro":"You are an early PM at Atlassian. It is the mid-2000s. Mike Cannon-Brookes and Scott Farquhar founded the company in Sydney with $10K of credit-card debt; the headquarters is on the other side of the Pacific from the vast majority of the addressable market. Jira and Confluence are gaining real traction with developer teams inside large enterprises.\n\nEvery enterprise software company at the time runs the same playbook: hire a US-based field-sales team, build out solutions engineering, push six-figure annual contracts, target the CIO. Atlassian''s competitors (Rally, VersionOne, IBM Rational) all do this. The two founders are 26 and 25 and have never been salespeople. The conventional wisdom from their VCs and advisors: hire a sales team, raise a B round, move to the US.","open_questions":["Hire the standard enterprise sales motion (and burn ~$5-10M of investment building it), or refuse and double down on self-serve product-led growth?","If self-serve only — how do you sell six-figure software to a Fortune 500 IT department without ever picking up the phone?","What''s the right pricing structure for self-serve enterprise — flat-rate tiers, per-seat, or per-team?","Does the headquarters stay in Sydney even as the customer base moves to the US — and what''s the cost of being 16 hours from your buyers?"],"closing":"Imagine you''re with Mike and Scott in 2008 in a Sydney office at 2am — your VCs in San Francisco are asking when the US sales team is getting hired.","decision":"Refuse to build a sales team. Every dollar that would have gone to AEs goes into the product, the website, and developer-facing content. Pricing is published on the website. A bank-card purchase replaces a procurement cycle. Atlassian stays headquartered in Sydney. The company runs profitably from year one. By the time of the December 2015 IPO, Atlassian is doing ~$350M in revenue with no traditional sales team and is profitable enough that the IPO raises almost no growth capital.","pullquote":"We''ve built a billion-dollar company without ever hiring a salesperson. The product is the sales team — everything else is overhead on the relationship the customer already wants.","pullquote_attribution":"Mike Cannon-Brookes / Scott Farquhar — paraphrased from Atlassian''s pre-IPO commentary and the Acquired podcast","outcomes":[{"stat":"0","label":"outbound salespeople through 2015 IPO","accent":true},{"stat":"$350M","label":"ARR at the time of IPO"},{"stat":"$4.37B","label":"valuation at NASDAQ IPO (Dec 2015)"},{"stat":"Sydney","label":"HQ — never moved despite US-dominated customer base"},{"stat":"Profitable","label":"from year one — no growth-at-all-costs funding required"}],"tradeoffs":[{"title":"Sales team vs. self-serve product","body":"A sales team accelerates large-deal velocity but adds permanent gross-margin drag and culture. Self-serve forces the product to do every job a salesperson would do — onboarding, expansion, renewals — and compounds product investment instead of headcount."},{"title":"Sydney HQ vs. US move","body":"Staying in Sydney meant cheaper engineering, a different talent pool, and a 16-hour gap to most customers. The cost: harder to recruit US executives; the benefit: distinct culture, no Bay Area salary arms-race, lower burn per engineer."},{"title":"Profitability vs. growth-at-all-costs","body":"Running profitably from year one limited the speed at which Atlassian could acquire customers but eliminated dilution and capital-market dependency. By IPO, the company didn''t need the public-market money — the IPO was a liquidity event for employees and investors, not a survival raise."},{"title":"Bottom-up adoption vs. top-down enterprise selling","body":"Selling to developers (who then carry the tool into their company) is a slower path than selling to CIOs but produces stickier deployments. Atlassian inverted the buying motion: by the time a procurement team noticed Jira, it was already running 200 teams inside the company."}],"per_dimension_truth":{"tradeoff":"Slower top-line growth and harder credibility with US enterprise buyers vs. structurally lower gross-margin drag, no dilution, and a culture that didn''t require Bay Area mimicry. They chose the latter and accepted the slower curve.","user":"Developers inside enterprises, not procurement officers. The buyer they served was the user, not the person with the budget — which meant the product had to do the buyer''s job (build the business case) itself.","alt":"Hiring a US sales team in 2008 would have accelerated revenue and likely required raising a B round + moving the HQ. The opposite trade. They were one of very few SaaS companies to refuse that path and still IPO at scale.","predict":"Slower revenue ramp than peers, profitability and capital efficiency well above peers, IPO with little fanfare and durable economics, and a playbook that every product-led-growth SaaS company would later try to copy."},"quote_type":"paraphrased","sources":[{"title":"The Atlassian IPO","url":"https://www.acquired.fm/episodes/the-atlassian-ipo","publisher":"Acquired Podcast","type":"podcast"},{"title":"Atlassian — Wikipedia","url":"https://en.wikipedia.org/wiki/Atlassian","type":"article"},{"title":"20 years of Atlassian, 20 lessons learned","url":"https://www.atlassian.com/blog/announcements/atlassian-founders-20-years-20-lessons","publisher":"Atlassian Blog","type":"blog"}],"tags":{"industry":"saas","region":"anz","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'nokia-burning-platform-2011',
  'weekly',
  '{"id":"nokia-burning-platform-2011","type":"weekly","iso_week":"","company":"Nokia","era":"February 2011","intro":"It is early February 2011. You are a senior PM at Nokia. Nokia still ships more phones than any company on earth (~30%+ global market share). But smartphone share is collapsing. The iPhone shipped in 2007, Android in 2008; by Q4 2010, Nokia''s Symbian-based smartphones are losing share month over month and engineers internally have been saying for years that Symbian cannot compete on touch.\n\nThe new CEO, Stephen Elop — recruited from Microsoft — is about to write a memo to the entire company. The memo will describe Nokia''s situation using the metaphor of a man standing on a burning oil platform who has to choose between certain death in the fire and a jump into the freezing sea. The memo will then preview an exclusive partnership with Microsoft to ship Windows Phone as Nokia''s primary smartphone OS, abandoning Symbian and Nokia''s own internal Linux-based MeeGo. The memo is going to leak.","open_questions":["Bet on Symbian (legacy moat, declining), Android (growing fast, but commoditized), Windows Phone (new, niche, partnership with ex-employer), or MeeGo (in-house but unproven)?","How public to be about the platform''s failure — internal honesty vs. signaling weakness to competitors, employees, and the supply chain?","What''s the cost of the partnership exclusivity — does committing fully to Windows Phone foreclose the Android option permanently?","Is the goal to save the smartphone business or to maintain Nokia as a viable hardware brand on any platform?"],"closing":"Imagine you''re at Nokia HQ in Espoo, Finland in late January 2011. The memo is going to leak in days; the partnership announcement is two weeks out.","decision":"Send the ''burning platform'' memo internally on Feb 8, 2011 — it leaks within hours. Announce the exclusive Microsoft Windows Phone partnership on Feb 11. Symbian is officially deprecated. MeeGo is killed. Android is explicitly ruled out — Elop''s stated reason is that Nokia would have been one of many Android OEMs, undifferentiated. Three years later, Nokia''s smartphone business is sold to Microsoft. By 2013, Nokia shipped only 4.4M phones vs. 463M in 2007 — a 99% collapse.","pullquote":"We are standing on a burning platform. And, we have more than one explosion — we have multiple points of scorching heat that are fuelling a blazing fire around us.","pullquote_attribution":"Stephen Elop, Nokia CEO — internal ''burning platform'' memo, February 8, 2011","outcomes":[{"stat":"463M → 4.4M","label":"phones shipped 2007 → 2013 (~99% collapse)","accent":true},{"stat":"−90%","label":"market value lost in 6 years"},{"stat":"$7.2B","label":"Microsoft purchase of Nokia''s phone business (2013)"},{"stat":"0","label":"Android phones shipped under the original Nokia (the option Elop ruled out)"},{"stat":"Symbian","label":"deprecated; MeeGo killed; Windows Phone never reached 5% global share"}],"tradeoffs":[{"title":"Windows Phone vs. Android","body":"Windows Phone gave Nokia differentiated positioning (only major Windows Phone OEM, deep partnership) but in a tiny ecosystem. Android gave commodity positioning in a winning ecosystem. Elop chose differentiation in a losing race over commodity in a winning one."},{"title":"Burning the legacy publicly vs. quiet transition","body":"The ''burning platform'' memo was internal honesty made public. It rallied some engineers and accelerated the cultural break from Symbian, but it also crushed enterprise customer confidence in Nokia phones for a generation. The memo was likely correct in tone and catastrophic in market consequence."},{"title":"Exclusive partnership vs. multi-platform hedging","body":"Going all-in with Microsoft simplified focus and won partnership economics. Hedging with both Windows Phone and Android would have diluted execution but preserved optionality. Elop''s bet was that hedging was the death of focus; the cost was no fallback when Windows Phone failed."},{"title":"Manufacturer-as-OEM vs. manufacturer-as-platform","body":"Underneath every choice was a deeper question: does Nokia control its own OS, or does it ship someone else''s? Killing MeeGo answered ''someone else''s'' permanently — and turned Nokia from a vertical-stack company into a contract OEM running a partnership economy."}],"per_dimension_truth":{"tradeoff":"Honest internal alignment + decisive platform bet (Windows Phone) vs. preserving market confidence + keeping Android in play. Elop chose alignment + commitment; market confidence collapsed and the chosen platform lost.","user":"Symbian''s legacy enterprise/feature-phone users were left without a credible migration path. The product was no longer for them; it was for a new (and as it turned out, non-existent) Windows-Phone-loving consumer.","alt":"Hedging with Android would have meant slower commitment but preserved a route to relevance. Multiple OEMs survived that transition (Samsung, LG, HTC). Nokia foreclosed that option in the same week it killed Symbian.","predict":"Short-term: brand collapse, supply-chain pain, employee exodus. Medium-term: Windows Phone fails to gain share, Nokia''s smartphone business becomes acquisition fodder. Long-term: the burning-platform memo becomes the case study in how to be right about the diagnosis and wrong about the treatment."},"quote_type":"verbatim","sources":[{"title":"Nokia CEO Stephen Elop rallies troops in brutally honest ''burning platform'' memo","url":"https://www.engadget.com/2011-02-08-nokia-ceo-stephen-elop-rallies-troops-in-brutally-honest-burnin.html","publisher":"Engadget","year":2011,"type":"article"},{"title":"Stephen Elop — Wikipedia","url":"https://en.wikipedia.org/wiki/Stephen_Elop","type":"article"},{"title":"Who Killed Nokia? Nokia Did","url":"https://knowledge.insead.edu/strategy/who-killed-nokia-nokia-did","publisher":"INSEAD Knowledge","type":"article"}],"tags":{"industry":"hardware","region":"eu","decade":"2010s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;

insert into scenarios (id, type, payload) values (
  'openai-chatgpt-launch-2022',
  'weekly',
  '{"id":"openai-chatgpt-launch-2022","type":"weekly","iso_week":"","company":"OpenAI","era":"November 2022","intro":"It is mid-November 2022. You are a senior PM at OpenAI. GPT-3.5 has been in private API access for over a year. Internally, a team has built a chat interface on top of it called ''Chat with GPT-3.5'' as a research demo — the product is not on the roadmap to ship publicly. The model has known issues: confident hallucination, sycophancy, jailbreaks, unsafe outputs.\n\nLeadership is debating whether to release the chat interface publicly as a free ''research preview.'' The cautious view: not ready, will produce embarrassing outputs at scale, will burn ~$700K/day in inference costs with no revenue, and will tip competitors (Google, Anthropic) to ship in response. The aggressive view: language models are already useful, real-world feedback is the only way to harden them, and being the first chat interface in the public mind is worth almost any short-term cost.","open_questions":["Ship the chat interface publicly as a ''research preview,'' or keep it API-only and let developers build the consumer experience?","Free or paid? Cost of inference is real; pricing it at $20/mo from day one would slow viral growth but contain burn.","How aggressive are the safety filters at launch — strict enough to prevent embarrassing outputs, or loose enough that the model actually feels useful?","How public to be about model limitations — full transparency upfront (manage expectations) vs. underplay (preserve magic)?"],"closing":"Imagine you''re in the OpenAI leadership room in mid-November 2022. NeurIPS is a few weeks out. You have a working chat interface and an internal disagreement about whether to ship.","decision":"Ship ChatGPT publicly on November 30, 2022 as a free ''research preview'' — no waitlist, no payment, available to anyone with an email. Frame the launch deliberately small: a single OpenAI blog post on a Wednesday during NeurIPS, no press tour, no demo videos. Sam Altman posts on Twitter that it is a ''very much a research release'' with ''a lot of limitations.'' One million users sign up in five days. Within two months, ChatGPT becomes the fastest-growing consumer product in history.","pullquote":"Today we launched ChatGPT. Try talking with it here. Language interfaces are going to be a big deal, I think. Talk to the computer (voice or text) and get what you want, for increasingly complex definitions of ''want.''","pullquote_attribution":"Sam Altman, OpenAI CEO — Twitter, November 30, 2022","outcomes":[{"stat":"1M","label":"users in 5 days — fastest consumer signup curve on record","accent":true},{"stat":"100M","label":"MAU within 2 months — fastest-growing consumer product in history"},{"stat":"~$700K/day","label":"estimated inference cost in the early days"},{"stat":"Code Red","label":"Google''s internal response — accelerating Bard/Gemini timelines"},{"stat":"$80B+","label":"OpenAI valuation within 18 months of launch"}],"tradeoffs":[{"title":"Ship rough vs. ship polished","body":"Shipping a research preview with visible flaws (hallucination, jailbreaks) meant accepting embarrassing screenshots in the press. The bet: real-world feedback at internet scale would improve the model faster than any amount of internal red-teaming. Polish would have cost the platform-defining moment."},{"title":"Free vs. paid","body":"Free unlocked viral growth but committed OpenAI to a massive subsidy. Pricing it would have constrained the audience and missed the cultural moment. They chose to eat the burn to own the mindshare."},{"title":"Quiet launch vs. loud launch","body":"A press-tour launch would have invited skeptical coverage of model limitations. A single blog post let the product speak for itself — and let the early-adopter screenshots do the marketing. Understatement was a deliberate amplifier."},{"title":"First-mover vs. wait-for-Google","body":"Google had stronger underlying research but more brand/regulatory risk in shipping a hallucinating chatbot. Going first was the riskiest move for safety reputation but the only way to define the category before a larger incumbent did."}],"per_dimension_truth":{"tradeoff":"Real-world feedback + category ownership vs. polish + safety reputation. They chose to ship rough and accept the safety drama as the cost of owning the conversation. Almost every later product decision (ChatGPT Plus, the API, Plugins, GPTs) flowed from the audience this single launch created.","user":"Curious early-adopters and developers — not a specific consumer segment. The launch worked precisely because the audience was ''anyone curious,'' which let the product define its own use cases (writing, coding, research, search) through user behavior rather than positioning.","alt":"Keeping the chat interface internal and shipping only the API would have ceded the consumer moment to whoever shipped the first chat wrapper. The opposite trade — and Google, Microsoft, and Anthropic all moved within 90 days because OpenAI shipped first.","predict":"Massive launch curve, safety scandals and embarrassing screenshots, an accelerated competitive race (Google Bard within 90 days), and a multi-year regime where ''ChatGPT'' becomes the consumer synonym for AI — with all the brand and regulatory consequences that follow."},"quote_type":"verbatim","sources":[{"title":"Introducing ChatGPT","url":"https://openai.com/index/chatgpt/","publisher":"OpenAI","year":2022,"type":"blog"},{"title":"ChatGPT — Wikipedia","url":"https://en.wikipedia.org/wiki/ChatGPT","type":"article"},{"title":"ChatGPT launched six months ago. Its impact — and fallout — is just beginning","url":"https://venturebeat.com/ai/chatgpt-launched-six-months-ago-its-impact-and-fallout-is-just-beginning-the-ai-beat","publisher":"VentureBeat","year":2023,"type":"article"}],"tags":{"industry":"ai-tools","region":"us","decade":"2020s"}}'::jsonb
) on conflict (id) do update set payload = excluded.payload, type = excluded.type;
